create table customer_addresses
(
    Id            int identity
        constraint PK_customer_addresses
            primary key,
    address       nvarchar(2000),
    province_id   int                                             not null,
    province_name nvarchar(255),
    district_id   int                                             not null,
    district_name nvarchar(255),
    ward_code     nvarchar(255)                                   not null,
    ward_name     nvarchar(255),
    phone_number  nvarchar(20),
    receiver_name nvarchar(255),
    is_default    bit       default CONVERT([bit], 0)             not null,
    user_id       uniqueidentifier
        constraint FK_customer_addresses_customers_user_id
            references customers,
    deleted_at    datetime2,
    created_at    datetime2 default '0001-01-01T00:00:00.0000000' not null,
    modified_at   datetime2
)
go

create index IX_customer_addresses_user_id
    on customer_addresses (user_id)
go

